#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        char s[130]; // enough for 120 + null
        scanf("%s", s);
        int present = 0;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') present++;
        }
        int maxPossible = present + (120 - N);
        if (maxPossible >= 90) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        string s; cin >> s;
        int present = 0;
        for (char c : s) if (c == '1') ++present;
        int maxPossible = present + (120 - N);
        cout << (maxPossible >= 90 ? "YES" : "NO") << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            int present = 0;
            for (int i = 0; i < s.length(); ++i) {
                if (s.charAt(i) == '1') present++;
            }
            int maxPossible = present + (120 - N);
            out.append(maxPossible >= 90 ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

